function solve(grid: number[][], k: number): number {
    const m = grid.length;
    const n = grid[0].length;
    const heap: [number, number, number, number][] = [];
    heap.push([0, 0, 0, k]);
    const visited: Map<string, number> = new Map();
    visited.set(`${0},${0},${k}`, 0);

    const directions = [[0, 1], [1, 0]];

    while (heap.length > 0) {
        heap.sort((a, b) => a[0] - b[0]);
        const [currentCost, i, j, remainingTp] = heap.shift()!;
        if (i === m - 1 && j === n - 1) {
            return currentCost;
        }
        const key = `${i},${j},${remainingTp}`;
        if (currentCost > (visited.get(key) || Infinity)) {
            continue;
        }

        // Normal moves
        for (const [di, dj] of directions) {
            const ni = i + di;
            const nj = j + dj;
            if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                const newCost = currentCost + grid[ni][nj];
                const newKey = `${ni},${nj},${remainingTp}`;
                if (!visited.has(newKey) || newCost < (visited.get(newKey) || Infinity)) {
                    visited.set(newKey, newCost);
                    heap.push([newCost, ni, nj, remainingTp]);
                }
            }
        }

        // Teleport moves
        if (remainingTp > 0) {
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if ((x !== i || y !== j) && grid[x][y] <= grid[i][j]) {
                        const newKey = `${x},${y},${remainingTp - 1}`;
                        if (!visited.has(newKey) || currentCost < (visited.get(newKey) || Infinity)) {
                            visited.set(newKey, currentCost);
                            heap.push([currentCost, x, y, remainingTp - 1]);
                        }
                    }
                }
            }
        }
    }

    return -1;
}
