import heapq

def solve(grid: list[list[int]], k: int) -> int:
    m, n = len(grid), len(grid[0])
    # Each state is (total_cost, i, j, remaining_teleports)
    heap = []
    heapq.heappush(heap, (0, 0, 0, k))
    # Visited structure: (i, j, remaining_teleports) -> min_cost
    visited = {}
    visited[(0, 0, k)] = 0

    directions = [(0, 1), (1, 0)]

    while heap:
        current_cost, i, j, remaining_tp = heapq.heappop(heap)
        if i == m - 1 and j == n - 1:
            return current_cost
        if current_cost > visited.get((i, j, remaining_tp), float('inf')):
            continue

        # Normal moves
        for di, dj in directions:
            ni, nj = i + di, j + dj
            if 0 <= ni < m and 0 <= nj < n:
                new_cost = current_cost + grid[ni][nj]
                if (ni, nj, remaining_tp) not in visited or new_cost < visited.get((ni, nj, remaining_tp), float('inf')):
                    visited[(ni, nj, remaining_tp)] = new_cost
                    heapq.heappush(heap, (new_cost, ni, nj, remaining_tp))

        # Teleport moves
        if remaining_tp > 0:
            for x in range(m):
                for y in range(n):
                    if (x != i or y != j) and grid[x][y] <= grid[i][j]:
                        if (x, y, remaining_tp - 1) not in visited or current_cost < visited.get((x, y, remaining_tp - 1), float('inf')):
                            visited[(x, y, remaining_tp - 1)] = current_cost
                            heapq.heappush(heap, (current_cost, x, y, remaining_tp - 1))

    return -1
